{"content": "#!/usr/bin/env python3
"""A tiny calculator CLI."""
import argparse
import sys

def format_num(n):
    if n.is_integer():
        return str(int(n))
    return str(n)

def main():
    parser = argparse.ArgumentParser(description="Tiny calculator CLI")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # Common parser for all subcommands
    def add_args(sub_parser):
        sub_parser.add_argument("a", type=float)
        sub_parser.add_argument("b", type=float)

    # add
    p_add = subparsers.add_parser("add")
    add_args(p_add)

    # sub
    p_sub = subparsers.add_parser("sub")
    add_args(p_sub)

    # mul
    p_mul = subparsers.add_parser("mul")
    add_args(p_mul)

    # div
    p_div = subparsers.add_parser("div")
    add_args(p_div)

    args = parser.parse_args()

    try:
        if args.command == "add":
            print(format_num(args.a + args.b))
        elif args.command == "sub":
            print(format_num(args.a - args.b))
        elif args.command == "mul":
            print(format_num(args.a * args.b))
        elif args.command == "div":
            if args.b == 0:
                print("Error: division by zero", file=sys.stderr)
                sys.exit(1)
            print(format_num(args.a / args.b))
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
